import { CheckCircle } from 'lucide-react';
import { Spinner } from './ds';

const STEPS = [
  { label: 'Parsing input',          note: 'Reading conversation context' },
  { label: 'Extracting entities',    note: 'Ticker · intent · horizon' },
  { label: 'Fetching market data',   note: 'Price · fundamentals · signals' },
  { label: 'Computing indicators',   note: 'Momentum · volume · sentiment' },
  { label: 'Generating response',    note: 'Building analyst brief' },
];

export default function Pipeline({ stage }) {
  return (
    <div style={{
      background: 'var(--white)', border: '1px solid var(--rule)',
      borderRadius: 'var(--r-md)', padding: '16px 18px',
      animation: 'up 0.2s ease',
    }}>
      <p style={{ fontSize: 10.5, fontWeight: 600, color: 'var(--ink-4)', letterSpacing: '0.09em', textTransform: 'uppercase', marginBottom: 14 }}>
        Processing pipeline
      </p>

      <div style={{ display: 'flex', flexDirection: 'column' }}>
        {STEPS.map((s, i) => {
          const done   = i < stage;
          const active = i === stage;
          const wait   = i > stage;
          return (
            <div key={i} style={{ display: 'flex', alignItems: 'flex-start', gap: 11, opacity: wait ? 0.3 : 1, transition: 'opacity 0.3s' }}>
              {/* Timeline */}
              <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', flexShrink: 0, paddingTop: 2 }}>
                {done
                  ? <CheckCircle size={16} color='var(--bull)' strokeWidth={2} />
                  : active
                    ? <Spinner size={16} color='var(--accent)' />
                    : <div style={{ width: 16, height: 16, borderRadius: '50%', border: '1.5px solid var(--rule-2)', background: 'var(--paper)' }} />
                }
                {i < STEPS.length - 1 && (
                  <div style={{ width: 1, height: 16, background: done ? 'var(--bull-rule)' : 'var(--rule)', marginTop: 2 }} />
                )}
              </div>

              {/* Text */}
              <div style={{ paddingBottom: i < STEPS.length - 1 ? 4 : 0, paddingTop: 1 }}>
                <p style={{ fontSize: 13, fontWeight: active ? 500 : 400, color: done ? 'var(--bull)' : active ? 'var(--ink)' : 'var(--ink-3)', margin: 0, transition: 'color 0.25s' }}>
                  {s.label}
                </p>
                {active && (
                  <p style={{ fontSize: 11.5, color: 'var(--ink-4)', margin: 0 }}>{s.note}…</p>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
